package com.wjx871.population.floating;
import com.wjx871.population.application.*;import com.wjx871.population.approval.*;import com.wjx871.population.audit.OperationLogService;import com.wjx871.population.common.BusinessException;import com.wjx871.population.material.*;import com.wjx871.population.person.Person;import com.wjx871.population.security.*;import jakarta.servlet.http.HttpServletRequest;import java.time.*;import java.time.temporal.ChronoUnit;import java.util.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @RequiredArgsConstructor public class FloatingResidenceService {
 private static final Set<String> REASONS=Set.of("EMPLOYMENT","STUDY","FAMILY","BUSINESS","OTHER_APPROVED"),PROOFS=Set.of("RENTAL_CONTRACT","PROPERTY_CERTIFICATE","EMPLOYER_ACCOMMODATION","SCHOOL_ACCOMMODATION","HOST_CONFIRMATION","OTHER_APPROVED"),CLOSE_REASONS=Set.of("LEFT_REGION","REGISTERED_LOCAL_HOUSEHOLD","PERSON_CANCELLED","DUPLICATE_RECORD","OTHER_APPROVED");
 private final FloatingResidenceMapper mapper;private final ApplicationService applications;private final BusinessApplicationMapper applicationMapper;private final ApplicationMaterialMapper materialMapper;private final ApprovalRequestMapper approvalMapper;private final ApprovalLogMapper approvalLogs;private final OperationLogService audit;private final ResidencePermitDatePolicy dates;private final FloatingRegistrationMaterialRequirementService floatingMaterials;private final ResidencePermitMaterialRequirementService permitMaterials;private final FloatingResidenceTransactionHook hook;private final SensitiveDataMaskingService masking;
 @Transactional public FloatingCreatedView createFloating(FloatingRegistrationRequest q,HttpServletRequest h){validateFloating(q);Person p=requireActivePerson(q.personId());ApplicationView a=applications.createSpecialized(appRequest(BusinessType.FLOATING_REGISTRATION,q.title(),q.personId(),q.reason(),q.remark(),null),h);FloatingApplication v=toFloating(a.applicationId(),q);mapper.insertFloatingApplication(v);return new FloatingCreatedView(a.applicationId(),a.applicationNo(),v.getFloatingApplicationId(),a.status().name());}
 @Transactional public FloatingCreatedView updateFloating(Long id,FloatingRegistrationRequest q){validateFloating(q);requireActivePerson(q.personId());BusinessApplication a=applications.require(id);applications.assertOwner(a,CurrentUserContext.requireUser());FloatingApplication old=mapper.findFloatingApplication(id).orElseThrow(()->notFound("流动登记专业详情不存在"));if(!old.getPersonId().equals(q.personId()))throw bad("登记人员不能修改");if(q.version()==null)throw bad("version 不能为空");FloatingApplication v=toFloating(id,q);if(mapper.updateFloatingApplication(v,q.version())==0)ApplicationService.conflict();ApplicationView av=applications.updateSpecialized(id,appRequest(BusinessType.FLOATING_REGISTRATION,q.title(),q.personId(),q.reason(),q.remark(),a.getVersion()));return new FloatingCreatedView(id,av.applicationNo(),old.getFloatingApplicationId(),av.status().name());}
 @Transactional(readOnly=true) public FloatingDetailView floatingApplication(Long id){BusinessApplication a=applications.require(id);applications.assertCanView(a,CurrentUserContext.requireUser());FloatingApplication v=mapper.findFloatingApplication(id).orElseThrow(()->notFound("流动登记专业详情不存在"));return new FloatingDetailView(ApplicationView.from(a),v,masked(mapper.findPerson(v.getPersonId()).orElse(null)),materials(id),a.getStatus()==ApplicationStatus.APPROVED&&"APPROVED".equals(v.getBusinessStatus()),a.getStatus()==ApplicationStatus.APPROVED?null:"申请尚未批准");}
 @Transactional public FloatingPopulation executeFloating(Long id,int version,HttpServletRequest h){BusinessApplication a=approved(id);FloatingApplication v=mapper.lockFloatingApplication(id).orElseThrow(()->notFound("流动登记专业详情不存在"));if(!"APPROVED".equals(v.getBusinessStatus())||v.getVersion()!=version)ApplicationService.conflict();Person p=requireActivePerson(v.getPersonId());assertRegion(v.getCurrentRegionCode());floatingMaterials.validateVerified(v);if(mapper.countActiveResidenceInRegion(p.getPersonId(),v.getCurrentRegionCode())>0)throw conflict("人员在当前区划已有有效本地户籍");if(mapper.countActiveFloating(p.getPersonId())>0)throw conflict("该人员已有当前流动登记");AuthenticatedUser u=CurrentUserContext.requireUser();FloatingPopulation f=new FloatingPopulation();f.setRegistrationNo(number("FR"));f.setSourceApplicationId(id);f.setPersonId(v.getPersonId());f.setSourceRegionCode(v.getSourceRegionCode());f.setSourceAddress(v.getSourceAddress());f.setCurrentRegionCode(v.getCurrentRegionCode());f.setCurrentAddress(v.getCurrentAddress());f.setResidenceReasonCode(v.getResidenceReasonCode());f.setResidenceProofType(v.getResidenceProofType());f.setArrivalDate(v.getArrivalDate());f.setPlannedLeaveDate(v.getPlannedLeaveDate());f.setRegistrationDate(dates.today());f.setEligibleFromDate(dates.eligibleFrom(v.getArrivalDate()));f.setDepartmentId(u.departmentId());f.setOperatorId(u.userId());mapper.insertFloatingPopulation(f);hook.afterFloatingInsert();if(mapper.updateFloatingApplicationStatus(id,"APPROVED","COMPLETED",u.userId(),f.getFloatingId())==0)ApplicationService.conflict();complete(a,u,h);return mapper.findFloating(f.getFloatingId()).orElse(f);}
 @Transactional(readOnly=true) public Page<FloatingPopulation> floatingSearch(String no,String person,String identity,String region,String status,boolean includeHistory,Pageable p){DataScopeCriteria s=DataScopeCriteria.current();List<FloatingPopulation> rows=mapper.searchFloating(no,person,identity,region,status,s,includeHistory,p.getPageSize(),p.getOffset());rows.forEach(this::mask);return new PageImpl<>(rows,p,mapper.countFloating(no,person,identity,region,status,s,includeHistory));}
 @Transactional(readOnly=true) public FloatingPopulation floating(Long id){FloatingPopulation f=mapper.findFloating(id).orElseThrow(()->notFound("流动登记不存在"));assertRegion(f.getCurrentRegionCode());mask(f);return f;}
 @Transactional public void closeFloating(Long id,CloseRegistrationRequest q,HttpServletRequest h){if(!CLOSE_REASONS.contains(q.reasonCode()))throw bad("无效的关闭原因");FloatingPopulation f=mapper.lockFloating(id).orElseThrow(()->notFound("流动登记不存在"));assertRegion(f.getCurrentRegionCode());String to="LEFT_REGION".equals(q.reasonCode())?"LEFT":"CANCELLED";if(mapper.closeFloating(id,to,q.reasonCode(),q.version())==0)ApplicationService.conflict();hook.afterFloatingClose();mapper.findActivePermitByFloating(id).ifPresent(p->{if(mapper.cancelPermit(p.getPermitId(),q.comment(),p.getVersion())==0)ApplicationService.conflict();log(p,null,"REGISTRATION_CLOSED","ACTIVE","CANCELLED",p.getValidUntil(),p.getValidUntil(),q.comment());});audit.recordTransactional(CurrentUserContext.requireUser().userId(),"FLOATING_REGISTRATION_CLOSE",h);}
 @Transactional public FloatingCreatedView createFirstIssue(PermitApplicationRequest q,HttpServletRequest h){if(q.floatingId()==null)throw bad("floatingId 不能为空");FloatingPopulation f=requireActiveFloating(q.floatingId());if(mapper.findActivePermitByPerson(f.getPersonId()).isPresent())throw conflict("该人员已有当前有效居住证");return createPermit("FIRST_ISSUE",BusinessType.RESIDENCE_PERMIT_FIRST_ISSUE,f,null,q,h);}
 @Transactional public FloatingCreatedView createEndorsement(Long permitId,PermitApplicationRequest q,HttpServletRequest h){ResidencePermit p=requireActivePermit(permitId);FloatingPopulation f=requireActiveFloating(p.getFloatingId());return createPermit("ENDORSEMENT",BusinessType.RESIDENCE_PERMIT_ENDORSEMENT,f,p,q,h);}
 @Transactional public FloatingCreatedView createCancellation(Long permitId,PermitApplicationRequest q,HttpServletRequest h){ResidencePermit p=requireActivePermit(permitId);FloatingPopulation f=mapper.findFloating(p.getFloatingId()).orElseThrow(()->notFound("流动登记不存在"));return createPermit("CANCELLATION",BusinessType.RESIDENCE_PERMIT_CANCELLATION,f,p,q,h);}
 @Transactional public FloatingCreatedView updatePermitApplication(Long id,PermitApplicationRequest q){if(q.version()==null)throw bad("version 不能为空");BusinessApplication a=applications.require(id);applications.assertOwner(a,CurrentUserContext.requireUser());PermitApplication v=mapper.findPermitApplication(id).orElseThrow(()->notFound("居住证专业详情不存在"));if(q.requestedValidFrom()!=null&&q.requestedValidUntil()!=null&&q.requestedValidUntil().isBefore(q.requestedValidFrom()))throw bad("申请有效期结束日期不能早于开始日期");v.setResidenceBasisCode(q.residenceBasisCode()==null?v.getResidenceBasisCode():q.residenceBasisCode());v.setRequestedValidFrom(q.requestedValidFrom());v.setRequestedValidUntil(q.requestedValidUntil());if(mapper.updatePermitApplication(v,q.version())==0)ApplicationService.conflict();ApplicationView av=applications.updateSpecialized(id,appRequest(a.getBusinessType(),q.title(),v.getPersonId(),q.reason(),q.remark(),a.getVersion()));return new FloatingCreatedView(id,av.applicationNo(),v.getPermitApplicationId(),av.status().name());}
 @Transactional(readOnly=true) public FloatingDetailView permitApplication(Long id){BusinessApplication a=applications.require(id);applications.assertCanView(a,CurrentUserContext.requireUser());PermitApplication v=mapper.findPermitApplication(id).orElseThrow(()->notFound("居住证专业详情不存在"));Object subject=v.getPermitId()==null?mapper.findFloating(v.getFloatingId()).orElse(null):mapper.findPermit(v.getPermitId()).orElse(null);return new FloatingDetailView(ApplicationView.from(a),v,subject,materials(id),a.getStatus()==ApplicationStatus.APPROVED&&"APPROVED".equals(v.getBusinessStatus()),a.getStatus()==ApplicationStatus.APPROVED?null:"申请尚未批准");}
 @Transactional public ResidencePermit issue(Long id,IssuePermitRequest q,HttpServletRequest h){BusinessApplication a=approved(id);PermitApplication v=lockPermitApplication(id,"FIRST_ISSUE",q.version());FloatingPopulation f=requireActiveFloating(v.getFloatingId());assertRegion(f.getCurrentRegionCode());if(dates.today().isBefore(f.getEligibleFromDate()))throw conflict("尚未达到居住证申领日期");if(mapper.findActivePermitByPerson(f.getPersonId()).isPresent())throw conflict("该人员已有当前有效居住证");permitMaterials.validateVerified(v,f);AuthenticatedUser u=CurrentUserContext.requireUser();ResidencePermit p=new ResidencePermit();p.setPermitNo(number("RP"));p.setPersonId(f.getPersonId());p.setFloatingId(f.getFloatingId());p.setSourceApplicationId(id);p.setIssueRegionCode(f.getCurrentRegionCode());p.setIssuingDepartmentId(u.departmentId());p.setIssuingAuthority(q.issuingAuthority());p.setIssueDate(dates.today());p.setValidFrom(dates.today());p.setValidUntil(dates.firstValidUntil(dates.today()));mapper.insertPermit(p);hook.afterPermitInsert();log(p,id,"ISSUE",null,"ACTIVE",null,p.getValidUntil(),null);hook.afterPermitLog();finishPermit(a,v,p.getPermitId(),u,h,"RESIDENCE_PERMIT_ISSUE");return mapper.findPermit(p.getPermitId()).orElse(p);}
 @Transactional public ResidencePermit endorse(Long id,int version,HttpServletRequest h){BusinessApplication a=approved(id);PermitApplication v=lockPermitApplication(id,"ENDORSEMENT",version);ResidencePermit p=requireActivePermit(v.getPermitId());FloatingPopulation f=requireActiveFloating(v.getFloatingId());assertRegion(f.getCurrentRegionCode());if(!dates.endorsementOpen(p.getValidUntil()))throw conflict("当前不在允许签注窗口");permitMaterials.validateVerified(v,f);LocalDate old=p.getValidUntil(),next=dates.endorsedUntil(old);if(mapper.endorsePermit(p.getPermitId(),old,next,p.getVersion())==0)ApplicationService.conflict();hook.afterPermitUpdate();log(p,id,"ENDORSE","ACTIVE","ACTIVE",old,next,null);finishPermit(a,v,p.getPermitId(),CurrentUserContext.requireUser(),h,"RESIDENCE_PERMIT_ENDORSE");return mapper.findPermit(p.getPermitId()).orElseThrow();}
 @Transactional public void cancelPermitApplication(Long id,int version,HttpServletRequest h){BusinessApplication a=approved(id);PermitApplication v=lockPermitApplication(id,"CANCELLATION",version);ResidencePermit p=requireActivePermit(v.getPermitId());FloatingPopulation f=mapper.findFloating(v.getFloatingId()).orElseThrow(()->notFound("流动登记不存在"));assertRegion(f.getCurrentRegionCode());permitMaterials.validateVerified(v,f);if(mapper.cancelPermit(p.getPermitId(),a.getReason(),p.getVersion())==0)ApplicationService.conflict();hook.afterPermitUpdate();log(p,id,"CANCEL","ACTIVE","CANCELLED",p.getValidUntil(),p.getValidUntil(),a.getReason());finishPermit(a,v,p.getPermitId(),CurrentUserContext.requireUser(),h,"RESIDENCE_PERMIT_CANCEL");}
 @Transactional(readOnly=true) public Page<ResidencePermit> permitSearch(String no,String person,String identity,String region,String status,LocalDate from,LocalDate to,Pageable p){DataScopeCriteria s=DataScopeCriteria.current();List<ResidencePermit> rows=mapper.searchPermits(no,person,identity,region,status,from,to,s,p.getPageSize(),p.getOffset());rows.forEach(this::mask);return new PageImpl<>(rows,p,mapper.countPermits(no,person,identity,region,status,from,to,s));}
 @Transactional(readOnly=true) public ResidencePermit permit(Long id){ResidencePermit p=mapper.findPermit(id).orElseThrow(()->notFound("居住证不存在"));assertRegion(p.getIssueRegionCode());mask(p);return p;}@Transactional(readOnly=true)public List<ResidencePermitLog> logs(Long id){permit(id);return mapper.permitLogs(id);}@Transactional(readOnly=true)public List<ExpiringPermitView> expiring(Integer days){LocalDate today=dates.today(),to=days==null?dates.warningUntil():today.plusDays(days);return mapper.expiring(today,to,DataScopeCriteria.current()).stream().map(p->new ExpiringPermitView(p.getPermitId(),masking.permit(p.getPermitNo()),p.getPersonName(),masking.identity(p.getIdentityNo()),p.getCurrentAddress(),p.getValidUntil(),ChronoUnit.DAYS.between(today,p.getValidUntil()),p.getStatus())).toList();}
 private FloatingCreatedView createPermit(String applyType,BusinessType type,FloatingPopulation f,ResidencePermit permit,PermitApplicationRequest q,HttpServletRequest h){assertRegion(f.getCurrentRegionCode());ApplicationView a=applications.createSpecialized(appRequest(type,q.title(),f.getPersonId(),q.reason(),q.remark(),null),h);PermitApplication v=new PermitApplication();v.setApplicationId(a.applicationId());v.setApplyType(applyType);v.setFloatingId(f.getFloatingId());v.setPermitId(permit==null?null:permit.getPermitId());v.setPersonId(f.getPersonId());v.setCurrentRegionCode(f.getCurrentRegionCode());v.setResidenceBasisCode(q.residenceBasisCode()==null?f.getResidenceReasonCode():q.residenceBasisCode());v.setRequestedValidFrom(q.requestedValidFrom());v.setRequestedValidUntil(q.requestedValidUntil());v.setBusinessStatus("DRAFT");if(v.getRequestedValidFrom()!=null&&v.getRequestedValidUntil()!=null&&v.getRequestedValidUntil().isBefore(v.getRequestedValidFrom()))throw bad("申请有效期结束日期不能早于开始日期");mapper.insertPermitApplication(v);return new FloatingCreatedView(a.applicationId(),a.applicationNo(),v.getPermitApplicationId(),a.status().name());}
 private PermitApplication lockPermitApplication(Long id,String type,int version){PermitApplication v=mapper.lockPermitApplication(id).orElseThrow(()->notFound("居住证专业详情不存在"));if(!type.equals(v.getApplyType())||!"APPROVED".equals(v.getBusinessStatus())||v.getVersion()!=version)ApplicationService.conflict();return v;}private BusinessApplication approved(Long id){BusinessApplication a=applications.require(id);if(a.getStatus()!=ApplicationStatus.APPROVED)throw conflict("申请尚未批准");return a;}private void finishPermit(BusinessApplication a,PermitApplication v,Long permit,AuthenticatedUser u,HttpServletRequest h,String action){if(mapper.updatePermitApplicationStatus(a.getApplicationId(),"APPROVED","COMPLETED",u.userId(),permit)==0)ApplicationService.conflict();hook.afterPermitLog();complete(a,u,h);audit.recordTransactional(u.userId(),action,h);}
 private void complete(BusinessApplication a,AuthenticatedUser u,HttpServletRequest h){if(applicationMapper.updateStatus(a.getApplicationId(),ApplicationStatus.APPROVED,ApplicationStatus.COMPLETED,a.getVersion())==0)ApplicationService.conflict();ApprovalRequest r=approvalMapper.selectByApplicationId(a.getApplicationId()).orElseThrow(()->conflict("审批请求不存在"));approvalLogs.insert(ApprovalLog.of(r.getApprovalId(),a.getApplicationId(),ApprovalAction.EXECUTE,"APPROVED","COMPLETED",u.userId(),"专业业务执行完成",audit.clientIp(h)));audit.recordTransactional(u.userId(),"FLOATING_RESIDENCE_EXECUTE",h);}
 private void log(ResidencePermit p,Long app,String action,String from,String to,LocalDate oldDate,LocalDate newDate,String reason){ResidencePermitLog l=new ResidencePermitLog();l.setPermitId(p.getPermitId());l.setApplicationId(app);l.setAction(action);l.setFromStatus(from);l.setToStatus(to);l.setOldValidUntil(oldDate);l.setNewValidUntil(newDate);AuthenticatedUser u=CurrentUserContext.getUserOrNull();l.setOperatorId(u==null?null:u.userId());l.setReason(reason);mapper.insertPermitLog(l);}
 private FloatingApplication toFloating(Long id,FloatingRegistrationRequest q){FloatingApplication v=new FloatingApplication();v.setApplicationId(id);v.setPersonId(q.personId());v.setSourceRegionCode(q.sourceRegionCode());v.setSourceAddress(q.sourceAddress());v.setCurrentRegionCode(q.currentRegionCode());v.setCurrentAddress(q.currentAddress());v.setResidenceReasonCode(q.residenceReasonCode());v.setResidenceProofType(q.residenceProofType());v.setArrivalDate(q.arrivalDate());v.setPlannedLeaveDate(q.plannedLeaveDate());v.setApplicantPhone(q.applicantPhone());v.setBusinessStatus("DRAFT");return v;}private ApplicationRequest appRequest(BusinessType t,String title,Long person,String reason,String remark,Integer version){return new ApplicationRequest(t,title,person,null,reason,remark,version);}private void validateFloating(FloatingRegistrationRequest q){if(!REASONS.contains(q.residenceReasonCode()))throw bad("无效的居住事由");if(!PROOFS.contains(q.residenceProofType()))throw bad("无效的居住证明类型");if(q.plannedLeaveDate()!=null&&q.plannedLeaveDate().isBefore(q.arrivalDate()))throw bad("计划离开日期不能早于到达日期");}
 private Person requireActivePerson(Long id){Person p=mapper.findPerson(id).orElseThrow(()->notFound("人员不存在"));if("CANCELLED".equals(p.getCurrentStatusCode())||"DECEASED".equals(p.getCurrentStatusCode()))throw conflict("已注销或死亡人员不能办理该业务");return p;}private FloatingPopulation requireActiveFloating(Long id){FloatingPopulation f=mapper.lockFloating(id).orElseThrow(()->notFound("流动登记不存在"));if(!"ACTIVE".equals(f.getStatus())||f.getCurrentFlag()==null)throw conflict("流动登记不是当前有效状态");return f;}private ResidencePermit requireActivePermit(Long id){ResidencePermit p=mapper.lockPermit(id).orElseThrow(()->notFound("居住证不存在"));if(!"ACTIVE".equals(p.getStatus())||p.getCurrentFlag()==null)throw conflict("居住证不是当前有效状态");return p;}private void assertRegion(String region){AuthenticatedUser u=CurrentUserContext.requireUser();if(u.dataScope()!=DataScope.ALL&&u.dataScope()!=DataScope.SELF&&!region.startsWith(u.regionCode().substring(0,Math.min(2,u.regionCode().length()))))throw new BusinessException(HttpStatus.FORBIDDEN,"无权访问该区域数据");}
 private List<MaterialView> materials(Long id){return materialMapper.selectByApplicationId(id).stream().map(MaterialView::from).toList();}private Object masked(Person p){if(p==null)return null;if(!masking.canViewFull()){p.setIdCard(masking.identity(p.getIdCard()));p.setPhone(masking.phone(p.getPhone()));p.setCurrentAddress(masking.address(p.getCurrentAddress()));}return p;}private void mask(FloatingPopulation f){if(!masking.canViewFull()){f.setIdentityNo(masking.identity(f.getIdentityNo()));f.setPhone(masking.phone(f.getPhone()));f.setCurrentAddress(masking.address(f.getCurrentAddress()));}}private void mask(ResidencePermit p){if(!masking.canViewFull()){p.setIdentityNo(masking.identity(p.getIdentityNo()));p.setPermitNo(masking.permit(p.getPermitNo()));p.setCurrentAddress(masking.address(p.getCurrentAddress()));}}private String number(String prefix){return prefix+"-"+dates.today().format(java.time.format.DateTimeFormatter.BASIC_ISO_DATE)+"-"+UUID.randomUUID().toString().substring(0,6).toUpperCase();}private BusinessException bad(String m){return new BusinessException(HttpStatus.BAD_REQUEST,m);}private BusinessException conflict(String m){return new BusinessException(HttpStatus.CONFLICT,m);}private BusinessException notFound(String m){return new BusinessException(HttpStatus.NOT_FOUND,m);}
}
